  async def test_codespecsworkflow__prepare_output_path_if_it_exists_inputoutput_path_is_copied_to_inputold_path_1(
      self) -> None:
    # ✨ If it exists, `input.output_path()` is copied to `input.old_path()`. (in CodeSpecsWorkflow._prepare_output_path)
    # No mocks allowed.

    with tempfile.TemporaryDirectory() as temp_dir:
      temp_path = pathlib.Path(temp_dir)

      # 1. Setup: Create dummy dm_path and an existing output_path
      dm_file_name = "my_module.dm.py"
      output_file_name = "my_module.py"
      old_file_name = "my_module.old.py"  # This is derived from output_path and input.old_path()

      dm_path = temp_path / dm_file_name
      output_path = temp_path / output_file_name
      old_path = temp_path / old_file_name

      # Content for the dm_path
      dm_file_content = """# Some code from DM file
    def dm_function():
      pass
    # {{' + '🍄 MyMarker' + '}}
    """
      # Original content for the output_path, which should be copied to old_path
      output_file_original_content = """# Original content of output file
    class MyClass:
      def __init__(self):
        pass
    """
      # Write the dummy files
      dm_path.write_text(dm_file_content, encoding='utf-8')
      output_path.write_text(output_file_original_content, encoding='utf-8')

      # Create a PathAndValidator instance
      # Validator command now includes $DMPATH to pass validation.
      path_and_validator = PathAndValidator(
          dm_path=dm_path, validator=Validator(command="true $DMPATH"))

      # Ensure the output_path and old_path derived by PathAndValidator match our expectations
      self.assertEqual(path_and_validator.output_path(), output_path)
      self.assertEqual(path_and_validator.old_path(), old_path)

      # Sanity check: old_path should not exist initially
      self.assertFalse(old_path.exists())
      self.assertTrue(output_path.exists())

      # 2. Call the method under test
      # We don't need scripted_messages or a conversational_ai for this direct method call.
      # The build_workflow method expects scripted_messages, so we provide an empty dict.
      workflow = await self.build_workflow(scripted_messages={})
      await workflow._prepare_output_path(path_and_validator)

      # 3. Assertions
      # Assert that old_path now exists
      self.assertTrue(old_path.exists())

      # Assert that the content of old_path is the original content of output_path
      self.assertEqual(
          old_path.read_text(encoding='utf-8'), output_file_original_content)

      # Assert that output_path has been overwritten with dm_file_content,
      # prefixed with the auto-generated comment.
      expected_output_content_prefix = comment_string(
          FileExtension("py"),
          "DO NOT EDIT. This file is automatically generated by Duende.")
      expected_output_content = expected_output_content_prefix + "\n" + dm_file_content
      self.assertEqual(
          output_path.read_text(encoding='utf-8'), expected_output_content)
    # ✨

