        import os  # For os.chmod
        import stat  # For file permissions
        from file_access_policy import FileAccessPolicy # For the base class

        # Define a custom FakeFileAccessPolicy that can be controlled
        class ControlledFakeFileAccessPolicy(FileAccessPolicy):

            def __init__(self, denied_paths: set[pathlib.Path]):
                # Store resolved paths to handle symlinks, relative/absolute paths consistently
                self.denied_paths = {p.resolve() for p in denied_paths}

            def allow_access(self, path: str) -> bool:
                # Resolve the path being checked to compare with denied_paths
                normalized_path = pathlib.Path(path).resolve()
                return normalized_path not in self.denied_paths


